function _ocultarChrome() {
  var t=document.getElementById('topbar'), n=document.getElementById('bottom-nav'), m=document.getElementById('main-content');
  if(t) t.style.display='none'; if(n) n.style.display='none';
  if(m){ m.style.paddingTop='0'; m.style.paddingBottom='0'; }
}
function _mostrarChrome() {
  var t=document.getElementById('topbar'), n=document.getElementById('bottom-nav'), m=document.getElementById('main-content');
  if(t) t.style.removeProperty('display'); 
  if(n) n.style.removeProperty('display');
  if(m){ m.style.paddingTop=''; m.style.paddingBottom=''; }
}

